"use client";

import Image from "next/image";
import Link from "next/link";
import { Heart, MapPin, BedDouble, Bath, Wifi, Zap, Droplets, Car, BadgeCheck, Star } from "lucide-react";
import { cn, formatPrice, getPropertyTypeLabel, getCoverPhoto, timeAgo } from "@/lib/utils";
import type { Property } from "@/types";

interface PropertyCardProps {
  property: Property;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
  className?: string;
}

export default function PropertyCard({
  property,
  isFavorite = false,
  onToggleFavorite,
  className,
}: PropertyCardProps) {
  const cover = getCoverPhoto(property);
  const price = property.price_monthly ?? property.price_sale;
  const priceLabel = property.listing_type === "sale" ? "Vann" : "/mwa";

  const amenicons = [
    { show: property.has_water,       icon: Droplets,  label: "Dlo"      },
    { show: property.has_electricity, icon: Zap,       label: "Kouran"   },
    { show: property.has_internet,    icon: Wifi,       label: "Wi-Fi"    },
    { show: property.has_parking,     icon: Car,        label: "Garaj"    },
  ];

  return (
    <article
      className={cn(
        "card group overflow-hidden flex flex-col",
        className
      )}
    >
      {/* Photo */}
      <div className="relative aspect-[4/3] overflow-hidden bg-slate-100">
        <Image
          src={cover}
          alt={property.title}
          fill
          className="object-cover group-hover:scale-105 transition-transform duration-300"
          sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
        />

        {/* Badges top-left */}
        <div className="absolute top-3 left-3 flex flex-wrap gap-1.5">
          <span className="badge bg-white/90 backdrop-blur-sm text-slate-700 shadow-sm">
            {getPropertyTypeLabel(property.property_type)}
          </span>
          {property.is_featured && (
            <span className="badge bg-sunset-500 text-white">
              <Star className="w-3 h-3 mr-0.5" />
              Vedèt
            </span>
          )}
        </div>

        {/* Listing type badge top-right */}
        <div className="absolute top-3 right-3 flex items-center gap-2">
          <span
            className={cn(
              "badge shadow-sm",
              property.listing_type === "sale"
                ? "bg-caribbean-700 text-white"
                : "bg-green-600 text-white"
            )}
          >
            {property.listing_type === "rent"
              ? "Lwaye"
              : property.listing_type === "sale"
              ? "Vann"
              : "Lwaye/Vann"}
          </span>
        </div>

        {/* Favorite button */}
        {onToggleFavorite && (
          <button
            onClick={(e) => {
              e.preventDefault();
              onToggleFavorite(property.id);
            }}
            className={cn(
              "absolute bottom-3 right-3 w-9 h-9 rounded-full flex items-center justify-center transition-all shadow-sm",
              isFavorite
                ? "bg-red-500 text-white"
                : "bg-white/90 backdrop-blur-sm text-slate-500 hover:text-red-500"
            )}
            aria-label={isFavorite ? "Retire nan favori" : "Ajoute nan favori"}
          >
            <Heart className={cn("w-4 h-4", isFavorite && "fill-current")} />
          </button>
        )}
      </div>

      {/* Content */}
      <div className="p-4 flex flex-col flex-1">
        {/* Location */}
        <div className="flex items-center gap-1.5 text-xs text-slate-500 mb-2">
          <MapPin className="w-3.5 h-3.5 text-caribbean-600 shrink-0" />
          <span>
            {property.location?.neighborhood
              ? `${property.location.neighborhood}, `
              : ""}
            {property.location?.commune}
          </span>
          {property.owner?.is_verified && (
            <span className="ml-auto flex items-center gap-1 text-caribbean-600">
              <BadgeCheck className="w-3.5 h-3.5" />
              Verifye
            </span>
          )}
        </div>

        {/* Title */}
        <Link href={`/listings/${property.id}`}>
          <h3 className="font-semibold text-slate-900 text-sm leading-snug line-clamp-2 hover:text-caribbean-700 transition-colors mb-3">
            {property.title}
          </h3>
        </Link>

        {/* Bedrooms + Bathrooms */}
        {(property.bedrooms > 0 || property.bathrooms > 0) && (
          <div className="flex items-center gap-3 text-xs text-slate-500 mb-3">
            {property.bedrooms > 0 && (
              <span className="flex items-center gap-1">
                <BedDouble className="w-3.5 h-3.5" />
                {property.bedrooms} chanm
              </span>
            )}
            {property.bathrooms > 0 && (
              <span className="flex items-center gap-1">
                <Bath className="w-3.5 h-3.5" />
                {property.bathrooms} sdb
              </span>
            )}
            {property.area_sqm && (
              <span className="text-slate-400">{property.area_sqm} m²</span>
            )}
          </div>
        )}

        {/* Amenities */}
        <div className="flex items-center gap-2 mb-3">
          {amenicons
            .filter((a) => a.show)
            .slice(0, 4)
            .map(({ icon: Icon, label }) => (
              <span
                key={label}
                title={label}
                className="w-6 h-6 rounded-lg bg-caribbean-50 flex items-center justify-center text-caribbean-600"
              >
                <Icon className="w-3.5 h-3.5" />
              </span>
            ))}
          {property.is_furnished && (
            <span className="text-xs text-caribbean-700 bg-caribbean-50 px-2 py-0.5 rounded-full">
              Mèble
            </span>
          )}
        </div>

        {/* Price + Time */}
        <div className="mt-auto flex items-end justify-between pt-3 border-t border-slate-100">
          <div>
            {price ? (
              <>
                <span className="text-lg font-bold text-caribbean-700">
                  {formatPrice(price, property.currency)}
                </span>
                <span className="text-xs text-slate-400 ml-1">{priceLabel}</span>
              </>
            ) : (
              <span className="text-sm text-slate-400 italic">Pri sou demann</span>
            )}
          </div>
          <span className="text-xs text-slate-400">
            {timeAgo(property.created_at)} de sa
          </span>
        </div>
      </div>
    </article>
  );
}
